ROOT CAUSE: The `server.listen()` call doesn't have any error handling for the "EADDRINUSE" error code. When the port is already in use, Node.js throws an unhandled exception that crashes the entire process instead of allowing graceful failure.

FIX:
```ts
export function startSseServer(taskStore: TaskStore): http.Server {
    const server = http.createServer((req, res) => { /* ... request handling ... */ });

    const SSE_PORT = parseInt(process.env["SSE_PORT"] ?? "3001", 10);
    const SSE_HOST = process.env["SSE_HOST"] ?? "127.0.0.1";

    server.listen(SSE_PORT, SSE_HOST, () => {
        logger.info({ host: SSE_HOST, port: SSE_PORT }, "SSE server listening");
    });

    server.on('error', (err) => {
        if (err.code === 'EADDRINUSE') {
            logger.warn({ host: SSE_HOST, port: SSE_PORT }, "SSE server port already in use, skipping SSE start");
            return;
        }
        throw err;
    });

    return server;
}
```

