import http from "http";
import logger from "../logger";

const DEFAULT_SSE_PORT = parseInt(process.env["SSE_PORT"] ?? "3001", 10);
const DEFAULT_SSE_HOST = process.env["SSE_HOST"] ?? "127.0.0.1";

export function startSseServer(
  taskStore: TaskStore,
  options?: { port?: number; host?: string }
): http.Server {
  const server = http.createServer((req, res) => { /* ...SSE routing... */ });
  const port = options?.port ?? DEFAULT_SSE_PORT;
  const host = options?.host ?? DEFAULT_SSE_HOST;

  server.listen(port, host, () => {
    logger.info({ host, port }, "SSE server listening");
  });

  // Handle listen errors gracefully
  server.on("error", (err: Error) => {
    if ("code" in err && err.code === "EADDRINUSE") {
